+                        "keyboard",
+                        selected_visible_index,
+                        &label,
+                    );
+                    return true;
+                }
+                false
+            }
+            KeyCode::Left => {
+                // Collapse if expanded.
+                if let Some(node) = self.node_at_visible_index_mut(selected_visible_index)
+                    && node.is_expanded()
+                    && node.has_children()
